def get_local_name(english_name: str, lang: str) -> str:
    """
    Given an English commodity name and a language code, returns the local name.
    Handles variety suffixes: 'Apple US' -> looks up 'apple' -> returns Telugu/Hindi/etc name + ' US'
    If name already contains non-Latin characters -> returns as-is (already local).
    Returns None if not found (caller should fall back to deep-translator).
    """
    if not english_name or not lang:
        return None

    import re
    # If already contains non-Latin chars -> it's already in a local script
    if re.search(r'[^\x00-\x7F]', english_name):
        return english_name

    name = english_name.strip()
    name_lower = name.lower()

    # 1. Direct match
    if name_lower in COMMODITY_DICT:
        return COMMODITY_DICT[name_lower].get(lang)

    # 2. Prefix match - handles "Apple US", "Tomato Local", "Mango Alphonso"
    for key in COMMODITY_DICT:
        if name_lower.startswith(key):
            suffix = name[len(key):].strip()   # e.g. "US", "Local", "Alphonso"
            local_root = COMMODITY_DICT[key].get(lang)
            if local_root:
                return f"{local_root} {suffix}".strip() if suffix else local_root

    # 3. Contained match - handles "Fresh Apple", "Indian Mango"
    for key in COMMODITY_DICT:
        if key in name_lower:
            local_root = COMMODITY_DICT[key].get(lang)
            if local_root:
                return local_root

    return None  # Not found -> caller uses deep-translator
